package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
)

var validLoadBalancerNameRegex = regexp.MustCompile(`^[a-zA-Z0-9\-_.]{2,128}$`)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, saves it to the specified file, and returns the result.
// Returns the combined output of the commands (formatted SLB data and any warnings) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName against Alibaba Cloud's official requirements
	if !validLoadBalancerNameRegex.MatchString(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: must be 2-128 characters, consisting of letters, digits, hyphens (-), underscores (_), and periods (.)")
	}

	// Validate outputFile path is syntactically correct
	if _, err := filepath.Abs(outputFile); err != nil {
		return "", fmt.Errorf("invalid outputFile path: %w", err)
	}
	// Check for null bytes which are invalid in all filesystems
	if bytes.ContainsRune([]byte(outputFile), '\000') {
		return "", fmt.Errorf("invalid outputFile path: contains null byte")
	}

	// Prepare aliyun command to fetch SLB data
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	// Create stdout pipe for aliyun to feed into jq
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, error details: %s", err, aliyunStderr.String())
	}

	// Prepare jq command to format the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout

	// Capture jq's output and errors
	jqStdout := &bytes.Buffer{}
	jqStderr := &bytes.Buffer{}
	jqCmd.Stdout = jqStdout
	jqCmd.Stderr = jqStderr

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w, aliyun error details: %s", err, aliyunStderr.String())
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Ensure jq process is cleaned up
		_ = jqCmd.Wait()
		combinedErr := fmt.Sprintf("aliyun command failed: %v, aliyun stderr: %s, jq stderr: %s",
			err, aliyunStderr.String(), jqStderr.String())
		return jqStdout.String(), fmt.Errorf("%w, details: %s", err, combinedErr)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		combinedErr := fmt.Sprintf("jq command failed: %v, aliyun stderr: %s, jq stderr: %s",
			err, aliyunStderr.String(), jqStderr.String())
		return jqStdout.String(), fmt.Errorf("%w, details: %s", err, combinedErr)
	}

	// Write formatted output to the specified file
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		return jqStdout.String(), fmt.Errorf("failed to write to output file: %w", err)
	}

	// Combine all output (formatted data + any warnings from commands)
	var combinedOutput bytes.Buffer
	combinedOutput.Write(jqStdout.Bytes())

	if aliyunStderr.Len() > 0 {
		combinedOutput.WriteString("\n--- Aliyun Warnings/Errors ---\n")
		combinedOutput.Write(aliyunStderr.Bytes())
	}

	if jqStderr.Len() > 0 {
		combinedOutput.WriteString("\n--- JQ Warnings/Errors ---\n")
		combinedOutput.Write(jqStderr.Bytes())
	}

	return combinedOutput.String(), nil
}

