import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Prevent path traversal and invalid output paths
	cleanedOutputPath := filepath.Clean(outputFile)
	if strings.HasPrefix(cleanedOutputPath, "..") || filepath.IsAbs(cleanedOutputPath) {
		return "", fmt.Errorf("invalid output file path: path traversal or absolute paths not allowed")
	}

	// Validate loadBalancerName for obvious invalid characters
	if strings.ContainsAny(loadBalancerName, "\n\r\t\000") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}

	// Open output file (truncates existing file, creates if missing)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outFile.Close()

	// Prepare jq command with proper argument passing
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdout = outFile

	// Create pipe for jq's stdin (connected to aliyun's stdout)
	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq input pipe: %w", err)
	}
	defer jqStdin.Close()

	// Capture jq's stderr output
	jqStderr := &bytes.Buffer{}
	jqCmd.Stderr = jqStderr

	// Start jq process (runs in background)
	if err := jqCmd.Start(); err != nil {
		return jqStderr.String(), fmt.Errorf("failed to start jq: %w", err)
	}

	// Prepare aliyun command with direct argument passing (no shell interpretation)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunCmd.Stdout = jqStdin

	// Capture aliyun's stderr output
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	// Run aliyun command (blocks until completion)
	aliyunErr := aliyunCmd.Run()
	// Close jq's stdin to signal end of input
	jqStdin.Close()

	// Wait for jq to finish processing input
	jqErr := jqCmd.Wait()

	// Combine and clean up stderr outputs
	combinedStderr := strings.TrimSpace(strings.Join([]string{aliyunStderr.String(), jqStderr.String()}, "\n"))

	// Handle errors from aliyun command first
	if aliyunErr != nil {
		return combinedStderr, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, combinedStderr)
	}

	// Handle errors from jq command
	if jqErr != nil {
		return combinedStderr, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, combinedStderr)
	}

	// Return combined stderr (empty string if no errors occurred)
	return combinedStderr, nil
}

