package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command to fetch SLB information
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command to format the output
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffers to capture stderr from both commands
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Connect stdout of aliyun to stdin of jq
	stdoutAliyun, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}
	cmdJq.Stdin = stdoutAliyun

	// Open the output file for writing
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// Start the jq command first to ensure it's ready to read input
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Start the aliyun command to produce output
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for aliyun command to complete
	errAliyun := cmdAliyun.Wait()

	// Wait for jq command to finish processing input
	errJq := cmdJq.Wait()

	// Collect any errors from both commands
	var errList []error
	if errAliyun != nil {
		errList = append(errList, fmt.Errorf("aliyun command failed: %w (stderr: %s)", errAliyun, aliyunStderr.String()))
	}
	if errJq != nil {
		errList = append(errList, fmt.Errorf("jq command failed: %w (stderr: %s)", errJq, jqStderr.String()))
	}

	// Return combined errors if any
	if len(errList) > 0 {
		return "", errors.Join(errList...)
	}

	// Read the output file content to return as result
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file '%s': %w", outputFile, err)
	}

	return string(content), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error executing command: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to '%s'\n", outputFile)
	fmt.Println("Exported content:")
	fmt.Println(result)
}

