func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Prepare the aliyun SLB command with the given load balancer name
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	// Prepare the jq command to filter the SLB response
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqStderr := &bytes.Buffer{}
	jqCmd.Stderr = jqStderr

	// Connect stdout of aliyun command to stdin of jq command
	stdoutPipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}
	defer stdoutPipe.Close()
	jqCmd.Stdin = stdoutPipe

	// Open the output file for writing (truncates if exists)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()
	jqCmd.Stdout = outFile

	// Start the aliyun command first
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun CLI: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Start the jq command to process the output
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process to avoid zombies
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq: %w, jq stderr: %s, aliyun stderr: %s", err, jqStderr.String(), aliyunStderr.String())
	}

	// Wait for aliyun to finish writing all output to the pipe
	if err := aliyunCmd.Wait(); err != nil {
		// Wait for jq to process remaining input before exiting
		_ = jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq to finish processing and writing to the output file
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, jq stderr: %s", err, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB information to %q", outputFile), nil
}

