package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, saves it to the specified file, and returns the formatted output.
// Returns the formatted SLB information and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to prevent invalid characters and empty output file
	if strings.ContainsRune(loadBalancerName, '\x00') || strings.ContainsRune(outputFile, '\x00') {
		return "", fmt.Errorf("invalid null character in input parameters")
	}
	if outputFile == "" {
		return "", fmt.Errorf("output file name cannot be empty")
	}

	// Create and configure aliyun CLI command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stderr pipe: %w", err)
	}

	// Start aliyun command execution
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Create and configure jq command with input from aliyun's output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}
	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stderr pipe: %w", err)
	}

	// Start jq command execution
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read jq's output streams
	jqOutputBytes, err := io.ReadAll(jqStdout)
	if err != nil {
		return "", fmt.Errorf("failed to read jq output: %w", err)
	}
	jqErrBytes, err := io.ReadAll(jqStderr)
	if err != nil {
		return string(jqOutputBytes), fmt.Errorf("failed to read jq errors: %w", err)
	}

	// Check jq command execution result
	if err := jqCmd.Wait(); err != nil {
		return string(jqOutputBytes), fmt.Errorf("jq command failed: %w, stderr: %s", err, string(jqErrBytes))
	}

	// Check aliyun command execution result
	if err := aliyunCmd.Wait(); err != nil {
		aliyunErrBytes, _ := io.ReadAll(aliyunStderr)
		return string(jqOutputBytes), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(aliyunErrBytes))
	}

	// Write formatted output to specified file
	if err := os.WriteFile(outputFile, jqOutputBytes, 0644); err != nil {
		return string(jqOutputBytes), fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the formatted SLB information
	return string(jqOutputBytes), nil
}

