// Returns the combined stderr output of both commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Check for invalid characters (control characters or null)
	hasInvalidChars := func(s string) bool {
		return strings.ContainsFunc(s, func(r rune) bool {
			return unicode.IsControl(r) || r == 0
		})
	}
	if hasInvalidChars(loadBalancerName) || hasInvalidChars(outputFile) {
		return "", fmt.Errorf("invalid characters in input parameters (control characters or null not allowed)")
	}

	// Open output file with standard write permissions
	outFile, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outFile.Close()

	// Initialize aliyun command with direct argument passing
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	// Initialize jq command with direct argument passing
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdout = outFile

	// Connect aliyun stdout to jq stdin
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	jqStderr := &bytes.Buffer{}
	jqCmd.Stderr = jqStderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Ensure aliyun command is cleaned up
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w, aliyun stderr: %s", err, aliyunStderr.String())
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Clean up jq command
		_ = jqCmd.Wait()
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunStderr.String(), jqStderr.String())
		return combinedErr, fmt.Errorf("aliyun command failed: %w, combined stderr: %s", err, combinedErr)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunStderr.String(), jqStderr.String())
		return combinedErr, fmt.Errorf("jq command failed: %w, combined stderr: %s", err, combinedErr)
	}

	// Combine stderr outputs (matches original behavior of returning combined shell output)
	combinedOutput := fmt.Sprintf("%s%s", aliyunStderr.String(), jqStderr.String())
	return combinedOutput, nil
}

