// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Open output file for writing (create if missing, truncate if exists)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Create pipe to connect aliyun stdout to jq stdin
	reader, writer := io.Pipe()
	defer reader.Close()
	defer writer.Close()

	// Configure aliyun command
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)
	aliyunCmd.Stdout = writer

	// Configure jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = reader
	jqCmd.Stdout = outFile

	// Capture stderr from both commands
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun start failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		if killErr := aliyunCmd.Process.Kill(); killErr != nil {
			fmt.Printf("warning: failed to kill aliyun process: %v\n", killErr)
		}
		aliyunCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("jq start failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for aliyun to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Clean up jq process if aliyun fails
		if killErr := jqCmd.Process.Kill(); killErr != nil {
			fmt.Printf("warning: failed to kill jq process: %v\n", killErr)
		}
		jqCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("aliyun execution failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Close writer end to signal jq that input is complete
	if err := writer.Close(); err != nil {
		fmt.Printf("warning: failed to close pipe writer: %v\n", err)
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq execution failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Return captured stderr (empty if no errors occurred)
	return stderrBuf.String(), nil
}

