	outputFileHandle, err := os.OpenFile(cleanedOutputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outputFileHandle.Close()
	jqCmd.Stdout = outputFileHandle

