package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to prevent null characters (invalid in command arguments/filenames)
	if strings.ContainsRune(loadBalancerName, 0) || strings.ContainsRune(outputFile, 0) {
		return "", fmt.Errorf("invalid null character in input parameters")
	}

	// Create aliyun command with direct arguments (no shell injection risk)
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Create jq command with direct arguments
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Buffer to capture stderr from both commands
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Open output file (truncates if exists, creates if not)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()
	jqCmd.Stdout = outFile

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Ensure aliyun process is cleaned up
		_ = aliyunCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Clean up jq process
		_ = jqCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to complete
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Return captured stderr (stdout is written to file)
	return stderrBuf.String(), nil
}

