// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to prevent path traversal and empty inputs
	if strings.Contains(outputFile, "../") || strings.Contains(outputFile, "..\\") {
		return "", fmt.Errorf("outputFile contains path traversal sequences")
	}
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Open output file with secure permissions (user read/write, group/others read)
	outFile, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outFile.Close()

	// Create aliyun command with direct argument passing (no shell interpretation)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stderr pipe: %w", err)
	}

	// Create jq command with direct argument passing
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqCmd.Stdout = outFile
	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stderr pipe: %w", err)
	}

	// Buffer to collect combined stderr output from both commands
	var stderrBuf bytes.Buffer

	// Copy aliyun's stderr to buffer (ignore copy errors, collect what we can)
	go func() {
		_, _ = io.Copy(&stderrBuf, aliyunStderr)
	}()

	// Copy jq's stderr to buffer
	go func() {
		_, _ = io.Copy(&stderrBuf, jqStderr)
	}()

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		stderrStr := stderrBuf.String()
		return stderrStr, fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderrStr)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		_ = aliyunCmd.Process.Kill()
		stderrStr := stderrBuf.String()
		return stderrStr, fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderrStr)
	}

	// Wait for commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	stderrStr := stderrBuf.String()

	// Check for command execution errors
	if aliyunErr != nil {
		return stderrStr, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, stderrStr)
	}
	if jqErr != nil {
		return stderrStr, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, stderrStr)
	}

	return stderrStr, nil
}

