package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
	"sync"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to prevent invalid characters and empty output file
	if strings.ContainsRune(loadBalancerName, 0) || strings.ContainsRune(outputFile, 0) {
		return "", fmt.Errorf("invalid null character in input parameters")
	}
	if outputFile == "" {
		return "", fmt.Errorf("output file name cannot be empty")
	}

	// Open output file with default permissions (0666, same as shell redirection)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Prepare aliyun command with direct argument passing (no shell)
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stdout pipe: %w", err)
	}
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stderr pipe: %w", err)
	}

	// Prepare jq command with direct argument passing, pipe aliyun's stdout to jq's stdin
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)
	jqCmd.Stdin = aliyunStdout
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get jq stdout pipe: %w", err)
	}
	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get jq stderr pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		aliyunCmd.Process.Kill()
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Capture stderr from both commands concurrently
	var stderrBuf bytes.Buffer
	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		io.Copy(&stderrBuf, aliyunStderr)
	}()

	go func() {
		defer wg.Done()
		io.Copy(&stderrBuf, jqStderr)
	}()

	// Write jq's output to the target file
	if _, err := io.Copy(outFile, jqStdout); err != nil {
		// Clean up both processes if file write fails
		aliyunCmd.Process.Kill()
		jqCmd.Process.Kill()
		wg.Wait()
		return stderrBuf.String(), fmt.Errorf("failed to write to output file: %w", err)
	}

	// Wait for commands to complete
	errAliyun := aliyunCmd.Wait()
	errJq := jqCmd.Wait()

	// Wait for stderr collection to finish
	wg.Wait()

	outputStr := stderrBuf.String()
	var combinedErr error

	// Aggregate errors from both commands
	if errAliyun != nil {
		combinedErr = fmt.Errorf("aliyun command failed: %w", errAliyun)
	}
	if errJq != nil {
		if combinedErr != nil {
			combinedErr = fmt.Errorf("%w; jq command failed: %w", combinedErr, errJq)
		} else {
			combinedErr = fmt.Errorf("jq command failed: %w", errJq)
		}
	}

	if combinedErr != nil {
		return outputStr, fmt.Errorf("command execution failed: %w, stderr: %s", combinedErr, outputStr)
	}

	return outputStr, nil
}

