package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, saves it to the specified file, and returns the result.
// Returns the formatted SLB information and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation: prevent null bytes (invalid in filenames/command arguments)
	if strings.Contains(loadBalancerName, "\x00") || strings.Contains(outputFile, "\x00") {
		return "", fmt.Errorf("invalid null character in input parameters")
	}

	// Create commands without shell to avoid injection risks
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr from both commands for error reporting
	var stderr bytes.Buffer
	aliyunCmd.Stderr = &stderr
	jqCmd.Stderr = &stderr

	// Pipe aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}
	defer aliyunStdout.Close()

	jqCmd.Stdin = aliyunStdout

	// Capture jq's formatted output
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for jq: %w", err)
	}
	defer jqStdout.Close()

	// Start commands in sequence
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderr.String())
	}

	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderr.String())
	}

	// Read formatted output from jq
	outputBytes, err := io.ReadAll(jqStdout)
	if err != nil {
		// Clean up both processes on read failure
		_ = aliyunCmd.Wait()
		_ = jqCmd.Wait()
		return string(outputBytes), fmt.Errorf("failed to read jq output: %w, stderr: %s", err, stderr.String())
	}

	// Wait for aliyun to complete and check for errors
	if err := aliyunCmd.Wait(); err != nil {
		return string(outputBytes), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderr.String())
	}

	// Wait for jq to complete and check for errors
	if err := jqCmd.Wait(); err != nil {
		return string(outputBytes), fmt.Errorf("jq command failed: %w, stderr: %s", err, stderr.String())
	}

	// Write output to specified file
	if err := os.WriteFile(outputFile, outputBytes, 0644); err != nil {
		return string(outputBytes), fmt.Errorf("failed to write to output file: %w", err)
	}

	return string(outputBytes), nil
}

// Example main function for testing purposes
func main() {
	// Replace with your actual SLB name and output path
	result, err := QuerySLBAndExport("my-slb-instance", "slb-output.json")
	if err != nil {
		fmt.Printf("Operation failed: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Success! Formatted SLB output:\n%s\n", result)
}

