func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file (truncate if exists, create if not)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Prepare the aliyun command
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr

	// Get stdout pipe for aliyun command
	stdoutAliyun, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stdout pipe: %w", err)
	}

	// Prepare the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	cmdJq.Stdin = stdoutAliyun
	cmdJq.Stdout = outFile
	var jqStderr bytes.Buffer
	cmdJq.Stderr = &jqStderr

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		// Kill aliyun process if jq fails to start
		if errKill := cmdAliyun.Process.Kill(); errKill != nil {
			return "", fmt.Errorf("failed to kill aliyun process after jq start failure: %w, original error: %w", errKill, err)
		}
		// Wait for aliyun to exit
		if errWait := cmdAliyun.Wait(); errWait != nil {
			return "", fmt.Errorf("failed to wait for aliyun after kill: %w, original error: %w", errWait, err)
		}
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Wait for jq command to complete
	if err := cmdJq.Wait(); err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed with exit code %d: %w, stderr: %s", exitErr.ExitCode(), err, jqStderr.String())
		}
		return "", fmt.Errorf("failed to wait for jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Wait for aliyun command to complete
	if err := cmdAliyun.Wait(); err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed with exit code %d: %w, stderr: %s", exitErr.ExitCode(), err, aliyunStderr.String())
		}
		return "", fmt.Errorf("failed to wait for aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Read the output file content to return as result
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error occurred: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", outputFile)
	fmt.Println("Result:")
	fmt.Println(result)
}

