package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the content written to the output file and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile cannot be empty")
	}

	// Check for null bytes (invalid in filenames and parameters)
	if strings.Contains(loadBalancerName, "\x00") || strings.Contains(outputFile, "\x00") {
		return "", fmt.Errorf("invalid null character in input parameters")
	}

	// Prepare aliyun CLI command with direct arguments (no shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Get stdout pipe from aliyun command
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	// Prepare jq command to format the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Get stdout pipe from jq command
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}

	// Create or truncate the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer func() {
		if closeErr := outFile.Close(); closeErr != nil {
			fmt.Fprintf(os.Stderr, "warning: failed to close output file '%s': %v\n", outputFile, closeErr)
		}
	}()

	// Capture output to both file and in-memory buffer
	var outputBuf bytes.Buffer
	multiWriter := io.MultiWriter(outFile, &outputBuf)

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return outputBuf.String(), fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Ensure aliyun command completes before returning
		_ = aliyunCmd.Wait()
		return outputBuf.String(), fmt.Errorf("failed to start jq command: %w, aliyun stderr: %s", err, aliyunStderr.String())
	}

	// Copy jq's output to both file and buffer
	if _, err := io.Copy(multiWriter, jqStdout); err != nil {
		// Clean up running commands
		_ = aliyunCmd.Wait()
		_ = jqCmd.Wait()
		return outputBuf.String(), fmt.Errorf("failed to copy jq output: %w, aliyun stderr: %s, jq stderr: %s", err, aliyunStderr.String(), jqStderr.String())
	}

	// Wait for aliyun command to finish and check for errors
	if err := aliyunCmd.Wait(); err != nil {
		return outputBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to finish and check for errors
	if err := jqCmd.Wait(); err != nil {
		return outputBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s, aliyun stderr: %s", err, jqStderr.String(), aliyunStderr.String())
	}

	// Return the content written to the output file
	return outputBuf.String(), nil
}

// Main function for testing purposes
func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		os.Exit(1)
	}

	result, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Success! Output written to %s\nContent:\n%s\n", os.Args[2], result)
}

